(() => {
    type ObjectType = {a: string; deep?: {b: string; c: number}; d?: ObjectType[]};
    return {build: () => createValidate<ObjectType>(), buildErrors: () => noErrs(createGetValidationErrors<ObjectType>())};
  })()

() => {
    const ot = RT.circular((self) =>
      RT.object({
        a: RT.string(),
        deep: RT.optional(RT.object({b: RT.string(), c: RT.number()})),
        d: RT.optional(RT.array(self)),
      })
    );
    return createValidate(ot);
  }

(() => {
    type ObjectType = {a: string; deep?: {b: string; c: number}; d?: ObjectType[]};
    return {
      build: () => {
        const check = typia.createIs<ObjectType>();
        return (v) => check(v);
      },
      buildErrors: () => {
        const val = typia.createValidate<ObjectType>();
        return (v) => val(v).success;
      },
    };
  })()

c(
    Type.Recursive((This) =>
      Type.Object({
        a: Type.String(),
        deep: Type.Optional(Type.Object({b: Type.String(), c: Type.Number()})),
        d: Type.Optional(Type.Array(This)),
      })
    )
  )

c(z.lazy(() => {
    const schema: z.ZodType = z.object({
      a: z.string(),
      deep: z.object({b: z.string(), c: z.number().finite()}).optional(),
      d: z.array(z.lazy(() => schema)).optional(),
    });
    return schema;
  }))
